510	ngx_http_upstream_create(ngx_http_request_t *r)
511	{
512	    ngx_http_upstream_t  *u;
513	
514	    u = r->upstream;
515	
516	    if (u && u->cleanup) {
517	        r->main->count++;
518	        ngx_http_upstream_cleanup(r);
519	    }
520	
521	    u = ngx_pcalloc(r->pool, sizeof(ngx_http_upstream_t));
522	    if (u == NULL) {
523	        return NGX_ERROR;
524	    }
525	
526	    r->upstream = u;
527	
528	    u->peer.log = r->connection->log;
529	    u->peer.log_error = NGX_ERROR_ERR;
530	
531	#if (NGX_HTTP_CACHE)
532	    r->cache = NULL;
533	#endif
534	
535	    u->headers_in.content_length_n = -1;
536	    u->headers_in.last_modified_time = -1;
537	
538	    return NGX_OK;
539	}
