542	void
543	ngx_http_upstream_init(ngx_http_request_t *r)
544	{
545	    ngx_connection_t     *c;
546	
547	    c = r->connection;
548	
549	    ngx_log_debug1(NGX_LOG_DEBUG_HTTP, c->log, 0,
550	                   "http init upstream, client timer: %d", c->read->timer_set);
551	
552	#if (NGX_HTTP_V2)
553	    if (r->stream) {
554	        ngx_http_upstream_init_request(r);
555	        return;
556	    }
557	#endif
558	
559	#if (NGX_HTTP_V3)
560	    if (c->quic) {
561	        ngx_http_upstream_init_request(r);
562	        return;
563	    }
564	#endif
565	
566	    if (c->read->timer_set) {
567	        ngx_del_timer(c->read);
568	    }
569	
570	    if (ngx_event_flags & NGX_USE_CLEAR_EVENT) {
571	
572	        if (!c->write->active) {
573	            if (ngx_add_event(c->write, NGX_WRITE_EVENT, NGX_CLEAR_EVENT)
574	                == NGX_ERROR)
575	            {
576	                ngx_http_finalize_request(r, NGX_HTTP_INTERNAL_SERVER_ERROR);
577	                return;
578	            }
579	        }
580	    }
581	
582	    ngx_http_upstream_init_request(r);
583	}
