585	
586	static void
587	ngx_http_upstream_init_request(ngx_http_request_t *r)
588	{
589	    ngx_str_t                      *host;
590	    ngx_uint_t                      i;
591	    ngx_resolver_ctx_t             *ctx, temp;
592	    ngx_http_cleanup_t             *cln;
593	    ngx_http_upstream_t            *u;
594	    ngx_http_core_loc_conf_t       *clcf;
595	    ngx_http_upstream_srv_conf_t   *uscf, **uscfp;
596	    ngx_http_upstream_main_conf_t  *umcf;
597	
598	    if (r->aio) {
599	        return;
600	    }
601	
602	    u = r->upstream;
603	
604	#if (NGX_HTTP_CACHE)
605	
606	    if (u->conf->cache) {
607	        ngx_int_t  rc;
608	
609	        rc = ngx_http_upstream_cache(r, u);
610	
611	        if (rc == NGX_BUSY) {
612	            r->write_event_handler = ngx_http_upstream_init_request;
613	            return;
614	        }
615	
616	        r->write_event_handler = ngx_http_request_empty_handler;
617	
618	        if (rc == NGX_ERROR) {
619	            ngx_http_finalize_request(r, NGX_HTTP_INTERNAL_SERVER_ERROR);
620	            return;
621	        }
622	
623	        if (rc == NGX_OK) {
624	            rc = ngx_http_upstream_cache_send(r, u);
625	
626	            if (rc == NGX_DONE) {
627	                return;
628	            }
629	
630	            if (rc == NGX_HTTP_UPSTREAM_INVALID_HEADER) {
631	                rc = NGX_DECLINED;
632	                r->cached = 0;
633	                u->buffer.start = NULL;
634	                u->cache_status = NGX_HTTP_CACHE_MISS;
635	                u->request_sent = 1;
636	            }
637	        }
638	
639	        if (rc != NGX_DECLINED) {
640	            ngx_http_finalize_request(r, rc);
641	            return;
642	        }
643	    }
644	
645	#endif
646	
647	    u->store = u->conf->store;
648	
649	    if (!u->store && !r->post_action && !u->conf->ignore_client_abort) {
650	
651	        if (r->connection->read->ready) {
652	            ngx_post_event(r->connection->read, &ngx_posted_events);
653	
654	        } else {
655	            if (ngx_handle_read_event(r->connection->read, 0) != NGX_OK) {
656	                ngx_http_finalize_request(r, NGX_HTTP_INTERNAL_SERVER_ERROR);
657	                return;
658	            }
659	        }
660	
661	        r->read_event_handler = ngx_http_upstream_rd_check_broken_connection;
662	        r->write_event_handler = ngx_http_upstream_wr_check_broken_connection;
663	    }
664	
665	    if (r->request_body) {
666	        u->request_bufs = r->request_body->bufs;
667	    }
668	
669	    if (u->create_request(r) != NGX_OK) {
670	        ngx_http_finalize_request(r, NGX_HTTP_INTERNAL_SERVER_ERROR);
671	        return;
672	    }
673	
674	    if (ngx_http_upstream_set_local(r, u, u->conf->local) != NGX_OK) {
675	        ngx_http_finalize_request(r, NGX_HTTP_INTERNAL_SERVER_ERROR);
676	        return;
677	    }
678	
679	    if (u->conf->socket_keepalive) {
680	        u->peer.so_keepalive = 1;
681	    }
682	
683	    clcf = ngx_http_get_module_loc_conf(r, ngx_http_core_module);
684	
685	    u->output.alignment = clcf->directio_alignment;
686	    u->output.pool = r->pool;
687	    u->output.bufs.num = 1;
688	    u->output.bufs.size = clcf->client_body_buffer_size;
689	
690	    if (u->output.output_filter == NULL) {
691	        u->output.output_filter = ngx_chain_writer;
692	        u->output.filter_ctx = &u->writer;
693	    }
694	
695	    u->writer.pool = r->pool;
696	
697	    if (r->upstream_states == NULL) {
698	
699	        r->upstream_states = ngx_array_create(r->pool, 1,
700	                                            sizeof(ngx_http_upstream_state_t));
701	        if (r->upstream_states == NULL) {
702	            ngx_http_finalize_request(r, NGX_HTTP_INTERNAL_SERVER_ERROR);
703	            return;
704	        }
705	
706	    } else {
707	
708	        u->state = ngx_array_push(r->upstream_states);
709	        if (u->state == NULL) {
710	            ngx_http_upstream_finalize_request(r, u,
711	                                               NGX_HTTP_INTERNAL_SERVER_ERROR);
712	            return;
713	        }
714	
715	        ngx_memzero(u->state, sizeof(ngx_http_upstream_state_t));
716	    }
717	
718	    cln = ngx_http_cleanup_add(r, 0);
719	    if (cln == NULL) {
720	        ngx_http_finalize_request(r, NGX_HTTP_INTERNAL_SERVER_ERROR);
721	        return;
722	    }
723	
724	    cln->handler = ngx_http_upstream_cleanup;
725	    cln->data = r;
726	    u->cleanup = &cln->handler;
727	
728	    if (u->resolved == NULL) {
729	
730	        uscf = u->conf->upstream;
731	
732	    } else {
733	
734	#if (NGX_HTTP_SSL)
735	        u->ssl_name = u->resolved->host;
736	#endif
737	
738	        host = &u->resolved->host;
739	
740	        umcf = ngx_http_get_module_main_conf(r, ngx_http_upstream_module);
741	
742	        uscfp = umcf->upstreams.elts;
743	
744	        for (i = 0; i < umcf->upstreams.nelts; i++) {
745	
746	            uscf = uscfp[i];
747	
748	            if (uscf->host.len == host->len
749	                && ((uscf->port == 0 && u->resolved->no_port)
750	                     || uscf->port == u->resolved->port)
751	                && ngx_strncasecmp(uscf->host.data, host->data, host->len) == 0)
752	            {
753	                goto found;
754	            }
755	        }
756	
757	        if (u->resolved->sockaddr) {
758	
759	            if (u->resolved->port == 0
760	                && u->resolved->sockaddr->sa_family != AF_UNIX)
761	            {
762	                ngx_log_error(NGX_LOG_ERR, r->connection->log, 0,
763	                              "no port in upstream \"%V\"", host);
764	                ngx_http_upstream_finalize_request(r, u,
765	                                               NGX_HTTP_INTERNAL_SERVER_ERROR);
766	                return;
767	            }
768	
769	            if (ngx_http_upstream_create_round_robin_peer(r, u->resolved)
770	                != NGX_OK)
771	            {
772	                ngx_http_upstream_finalize_request(r, u,
773	                                               NGX_HTTP_INTERNAL_SERVER_ERROR);
774	                return;
775	            }
776	
777	            ngx_http_upstream_connect(r, u);
778	
779	            return;
780	        }
781	
782	        if (u->resolved->port == 0) {
783	            ngx_log_error(NGX_LOG_ERR, r->connection->log, 0,
784	                          "no port in upstream \"%V\"", host);
785	            ngx_http_upstream_finalize_request(r, u,
786	                                               NGX_HTTP_INTERNAL_SERVER_ERROR);
787	            return;
788	        }
789	
790	        temp.name = *host;
791	
792	        ctx = ngx_resolve_start(clcf->resolver, &temp);
793	        if (ctx == NULL) {
794	            ngx_http_upstream_finalize_request(r, u,
795	                                               NGX_HTTP_INTERNAL_SERVER_ERROR);
796	            return;
797	        }
798	
799	        if (ctx == NGX_NO_RESOLVER) {
800	            ngx_log_error(NGX_LOG_ERR, r->connection->log, 0,
801	                          "no resolver defined to resolve %V", host);
802	
803	            ngx_http_upstream_finalize_request(r, u, NGX_HTTP_BAD_GATEWAY);
804	            return;
805	        }
806	
807	        ctx->name = *host;
808	        ctx->handler = ngx_http_upstream_resolve_handler;
809	        ctx->data = r;
810	        ctx->timeout = clcf->resolver_timeout;
811	
812	        u->resolved->ctx = ctx;
813	
814	        if (ngx_resolve_name(ctx) != NGX_OK) {
815	            u->resolved->ctx = NULL;
816	            ngx_http_upstream_finalize_request(r, u,
817	                                               NGX_HTTP_INTERNAL_SERVER_ERROR);
818	            return;
819	        }
820	
821	        return;
822	    }
823	
824	found:
